+    })()",
+    );
+    assert_eq!(result, "/api/v1");
+}
+
+// ─── ClientRequest.write accumulates body ───────────────────────────────────
+
+#[test]
+fn write_accumulates_body() {
+    let result = eval_http(
+        r"(() => {
+        const req = http.request({ hostname: 'example.com', path: '/' });
